  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ------------------------------------------------------\n// 1. USERS (The Clients using the Mobile App)\n// ------------------------------------------------------\nmodel User {\n  id                String   @id @default(uuid())\n  email             String   @unique\n  password          String\n  name              String\n  createdAt         DateTime @default(now())\n  profilePictureUrl String?\n\n  // --- STRIPE UPDATE ---\n  stripeCustomerId String? @unique // Saves their credit card profile!\n\n  subscriptions Subscription[]\n  usedCodes     AccessCode[]\n\n  // --- FORUM UPDATE ---\n  posts    Post[]\n  comments Comment[]\n}\n\n// ------------------------------------------------------\n// 2. COACHES (The Admins using the Web Dashboard)\n// ------------------------------------------------------\nmodel Coach {\n  id                String  @id @default(uuid())\n  name              String\n  email             String  @unique\n  password          String\n  specialty         String\n  bio               String?\n  profilePictureUrl String?\n\n  // --- STRIPE UPDATE ---\n  subscriptionPrice Float @default(19.99) // Allows coaches to set their own price!\n\n  // Relationships\n  videos          Video[]\n  subscriptions   Subscription[]\n  accessCodes     AccessCode[]\n  recommendations Recommendation[]\n\n  // --- FORUM UPDATE ---\n  posts    Post[]\n  comments Comment[]\n}\n\n// ------------------------------------------------------\n// 3. VIDEOS (Uploaded by Coaches)\n// ------------------------------------------------------\nmodel Video {\n  id        String   @id @default(uuid())\n  title     String\n  url       String // This will hold the Vimeo link\n  category  String\n  createdAt DateTime @default(now())\n\n  // Relationship: Belongs to a specific Coach\n  coachId String\n  coach   Coach  @relation(fields: [coachId], references: [id])\n}\n\n// ------------------------------------------------------\n// 4. SUBSCRIPTIONS (Links a User to a Coach)\n// ------------------------------------------------------\nmodel Subscription {\n  id     String @id @default(uuid())\n  status String // e.g., 'pending', 'active', 'expired', 'cancelled'\n\n  // --- STRIPE UPDATE ---\n  stripeSubscriptionId String? @unique // Links this database row to the actual Stripe receipt\n\n  startDate DateTime @default(now())\n  endDate   DateTime\n\n  // Relationships: Belongs to one User and one Coach\n  userId  String\n  user    User   @relation(fields: [userId], references: [id])\n  coachId String\n  coach   Coach  @relation(fields: [coachId], references: [id])\n}\n\n// ------------------------------------------------------\n// 5. ACCESS CODES (Given by Coaches to real-life clients)\n// ------------------------------------------------------\nmodel AccessCode {\n  id        String    @id @default(uuid())\n  code      String    @unique\n  usedAt    DateTime? // If null, the code hasn't been used yet\n  createdAt DateTime  @default(now())\n\n  // Relationships\n  coachId String\n  coach   Coach   @relation(fields: [coachId], references: [id])\n  usedBy  String? // ID of the User who redeemed it\n  user    User?   @relation(fields: [usedBy], references: [id])\n}\n\n// ------------------------------------------------------\n// 6. RECOMMENDATIONS (Coach's text/links for the 4th Tab)\n// ------------------------------------------------------\nmodel Recommendation {\n  id        String   @id @default(uuid())\n  type      String // e.g., 'text', 'equipment_link'\n  content   String // The actual text advice or the URL for the equipment\n  createdAt DateTime @default(now())\n\n  // Relationship: Belongs to a specific Coach\n  coachId String\n  coach   Coach  @relation(fields: [coachId], references: [id])\n}\n\n// ------------------------------------------------------\n// 7. POSTS (Forum Questions / Discussions)\n// ------------------------------------------------------\nmodel Post {\n  id        String   @id @default(uuid())\n  title     String\n  content   String\n  createdAt DateTime @default(now())\n\n  // The Author (Can be EITHER a User OR a Coach)\n  userId  String?\n  user    User?   @relation(fields: [userId], references: [id])\n  coachId String?\n  coach   Coach?  @relation(fields: [coachId], references: [id])\n\n  // A post can have many comments\n  comments Comment[]\n}\n\n// ------------------------------------------------------\n// 8. COMMENTS (Replies to Forum Posts)\n// ------------------------------------------------------\nmodel Comment {\n  id        String   @id @default(uuid())\n  content   String\n  createdAt DateTime @default(now())\n\n  // Which Post this comment belongs to\n  postId String\n  post   Post   @relation(fields: [postId], references: [id], onDelete: Cascade)\n\n  // The Author (Can be EITHER a User OR a Coach)\n  userId  String?\n  user    User?   @relation(fields: [userId], references: [id])\n  coachId String?\n  coach   Coach?  @relation(fields: [coachId], references: [id])\n}\n",
